// resources insert (via upsertGenericResourceTx) and for committing the tx.
// Splitting this out lets UpsertBatch dispatch typed inserts per item without
// opening a per-item transaction.
func (s *Store) upsertCapabilitiesTx(tx *sql.Tx, id string, obj map[string]any, data json.RawMessage) error {
	if _, err := tx.Exec(
		`INSERT INTO capabilities (id, accounts_id, data, synced_at)
		 VALUES (?, ?, ?, ?)
		 ON CONFLICT(id) DO UPDATE SET accounts_id = excluded.accounts_id, data = excluded.data, synced_at = excluded.synced_at`,
		id,
		string(data),
		time.Now(),
		lookupFieldValue(obj, "accounts_id"),
	); err != nil {
		return fmt.Errorf("insert into capabilities: %w", err)
	}

	return nil
}

